import React, { useMemo } from 'react';
import { Routes, Route, Navigate, useNavigate, useLocation } from 'react-router-dom';


export default function RegisterPage() {
    const nav = useNavigate();

    const [form, setForm] = React.useState({
        email: '',
        password: '',
        firstName: '',
        lastName: '',
    });

    const [responseMessage, setResponseMessage] = React.useState(null);

    const [loading, setLoading] = React.useState(false);

    const handleChange = (e) => {
        setForm({ ...form, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setResponseMessage(null);

        try {
            const resp = await fetch('https://manuscriptmagic.fowkes.xyz/services/register.php', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify(form),
            });
            const data = await resp.json();
            setResponseMessage(data);
        }
        catch (error) {
            setResponseMessage({ success: false, message: 'An error occurred. Please try again.' });
        }
        finally {
            setLoading(false);
        }};




 return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-slate-50 to-slate-100 flex items-center justify-center px-4 py-12">
      <div className="w-full max-w-xl bg-white border border-slate-200 rounded-2xl shadow-sm p-8">
        <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight">
          Create your account
        </h1>
        <p className="mt-2 text-slate-500">
          Enter your details to register.
        </p>

        <form onSubmit={handleSubmit} className="mt-8 space-y-5">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700">
                First Name <span className="text-red-500">*</span>
              </label>
              <input
                value={form.firstName}
                onChange= {handleChange}
                placeholder="First name"
                className="mt-2 w-full border border-slate-200 rounded-md px-3 py-2 outline-none focus:ring-2 focus:ring-blue-200"
                autoComplete="given-name"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700">
                Last Name <span className="text-red-500">*</span>
              </label>
              <input
                value={form.lastName}
                onChange= {handleChange}
                placeholder="Last name"
                className="mt-2 w-full border border-slate-200 rounded-md px-3 py-2 outline-none focus:ring-2 focus:ring-blue-200"
                autoComplete="family-name"
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700">
              Email <span className="text-red-500">*</span>
            </label>
            <input
              type = "email"
              value={form.email}
              onChange= {handleChange}
              placeholder="you@email.com"
              className="mt-2 w-full border border-slate-200 rounded-md px-3 py-2 outline-none focus:ring-2 focus:ring-blue-200"
              autoComplete="email"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700">
              Password <span className="text-red-500">*</span>
            </label>
            <input
              type="password"
              value={form.password}
              onChange= {handleChange}
              placeholder="At least 8 characters"
              className="mt-2 w-full border border-slate-200 rounded-md px-3 py-2 outline-none focus:ring-2 focus:ring-blue-200"
              autoComplete="new-password"
            />
          </div>

          {error ? <div className="text-sm text-red-600">{error}</div> : null}

          <button
            type="submit"
            disabled={loading}
            className={[
              'w-full py-3 rounded-md text-white font-semibold',
              loading ? 'bg-blue-600 hover:bg-blue-700' : 'bg-slate-300 cursor-not-allowed',
            ].join(' ')}
          >
            {loading ? 'Creating account…' : 'Register'}
          </button>

          <div className="text-sm text-slate-600 text-center">
            Already have an account?{' '}
            <Link to="/login" className="text-blue-700 hover:underline">
              Sign in
            </Link>
          </div>

          {!API_BASE ? (
            <div className="text-xs text-slate-500 text-center">
              Dev mode: <code>REACT_APP_API_BASE_URL</code> not set, using mock register.
            </div>
          ) : null}
        </form>
      </div>
    </div>
  );
}
